{
  "name": "EthicsGuard: UK Research Reviewer",
  "description": "A specialized AI assistant designed to help UK students review their research ethical approval forms against standard institutional checklists, identifying inconsistencies and areas for improvement.",
  "requestFramePermissions": ["camera"]
}

export interface FeedbackItem {
  section: string;
  status: 'compliant' | 'warning' | 'danger';
  observation: string;
  recommendation: string;
}

export interface AnalysisResult {
  summary: string;
  methodologyCritique: string;
  tableAnalysis: {
    table3: string;
    table6: string;
  };
  inconsistencies: string[];
  checklistFeedback: FeedbackItem[];
  overallVerdict: 'Ready' | 'Needs Revisions' | 'Requires Major Changes';
}

export interface Attachment {
  file: File;
  preview: string;
  base64: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";

export const analyzeEthicsForm = async (text: string, images: string[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const parts: any[] = [{ text: `Student Submission Content: ${text}` }];

  images.forEach(img => {
    parts.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: img.split(',')[1] // remove data:image/jpeg;base64,
      }
    });
  });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts }],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        thinkingConfig: { thinkingBudget: 32768 },
        responseMimeType: "application/json"
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

import React from 'react';

