import React from 'react';
import { AnalysisResult } from '../types';

interface AnalysisViewProps {
  result: AnalysisResult;
}

export const AnalysisView: React.FC<AnalysisViewProps> = ({ result }) => {
  const getStatusColor = (status: string) => {
    switch (status) {
      case 'compliant': return 'bg-green-100 text-green-800 border-green-200';
      case 'warning': return 'bg-amber-100 text-amber-800 border-amber-200';
      case 'danger': return 'bg-red-100 text-red-800 border-red-200';
      default: return 'bg-slate-100 text-slate-800 border-slate-200';
    }
  };

  const getVerdictColor = (verdict: string) => {
    switch (verdict) {
      case 'Ready': return 'text-green-600';
      case 'Needs Revisions': return 'text-amber-600';
      case 'Requires Major Changes': return 'text-red-600';
      default: return 'text-slate-600';
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Overview Section */}
      <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
        <div className="flex justify-between items-start mb-4">
          <h2 className="text-2xl font-bold text-slate-800">Review Summary</h2>
          <span className={`px-4 py-1 rounded-full text-sm font-bold border ${getVerdictColor(result.overallVerdict)}`}>
            {result.overallVerdict}
          </span>
        </div>
        <p className="text-slate-600 leading-relaxed mb-6">{result.summary}</p>

        <div className="grid md:grid-cols-2 gap-4">
          <div className="p-4 bg-indigo-50 rounded-xl border border-indigo-100">
            <h3 className="font-bold text-indigo-900 mb-2 flex items-center">
              <i className="fas fa-microscope mr-2"></i> Methodology Critique
            </h3>
            <p className="text-sm text-indigo-800 leading-relaxed">{result.methodologyCritique}</p>
          </div>
          <div className="p-4 bg-purple-50 rounded-xl border border-purple-100">
            <h3 className="font-bold text-purple-900 mb-2 flex items-center">
              <i className="fas fa-table mr-2"></i> Table 3 & 6 Analysis
            </h3>
            <div className="space-y-2 text-sm text-purple-800">
              <p><strong>Table 3:</strong> {result.tableAnalysis.table3}</p>
              <p><strong>Table 6:</strong> {result.tableAnalysis.table6}</p>
            </div>
          </div>
        </div>
      </section>

      {/* Inconsistencies Section */}
      {result.inconsistencies.length > 0 && (
        <section className="bg-red-50 p-6 rounded-2xl border border-red-100">
          <h2 className="text-xl font-bold text-red-900 mb-4 flex items-center">
            <i className="fas fa-exclamation-triangle mr-2"></i> Critical Inconsistencies
          </h2>
          <ul className="space-y-2">
            {result.inconsistencies.map((inc, i) => (
              <li key={i} className="flex items-start text-red-800 text-sm">
                <span className="mr-2 font-bold">•</span>
                {inc}
              </li>
            ))}
          </ul>
        </section>
      )}

      {/* Checklist Detailed Feedback */}
      <section>
        <h2 className="text-xl font-bold text-slate-800 mb-4">Checklist Compliance</h2>
        <div className="grid gap-4">
          {result.checklistFeedback.map((item, i) => (
            <div key={i} className={`p-4 rounded-xl border ${getStatusColor(item.status)}`}>
              <div className="flex justify-between items-center mb-2">
                <h4 className="font-bold">{item.section}</h4>
                <i className={`fas ${item.status === 'compliant' ? 'fa-check-circle' : 'fa-exclamation-circle'}`}></i>
              </div>
              <p className="text-sm mb-2 font-medium opacity-90">{item.observation}</p>
              {item.recommendation && (
                <div className="mt-2 pt-2 border-t border-black border-opacity-10">
                  <p className="text-xs font-bold uppercase tracking-wider opacity-70 mb-1">Recommendation</p>
                  <p className="text-sm italic">{item.recommendation}</p>
                </div>
              )}
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { FileUpload } from './components/FileUpload';
import { AnalysisView } from './components/AnalysisView';
import { analyzeEthicsForm } from './services/geminiService';
import { AnalysisResult, Attachment } from './types';

const App: React.FC = () => {
  const [inputText, setInputText] = useState('');
  const [attachments, setAttachments] = useState<Attachment[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFiles = useCallback((files: FileList) => {
    Array.from(files).slice(0, 5).forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAttachments(prev => [
          ...prev, 
          { file, preview: URL.createObjectURL(file), base64: reader.result as string }
        ]);
      };
      reader.readAsDataURL(file);
    });
  }, []);

  const handleSubmit = async () => {
    if (!inputText && attachments.length === 0) {
      setError("Please provide some text or screenshots of your ethics form.");
      return;
    }

    setIsAnalyzing(true);
    setError(null);
    setResult(null);

    try {
      const images = attachments.map(a => a.base64);
      const analysis = await analyzeEthicsForm(inputText, images);
      setResult(analysis);
    } catch (err) {
      setError("Failed to analyze the form. Please check your API configuration or try again later.");
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const reset = () => {
    setResult(null);
    setInputText('');
    setAttachments([]);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Navigation */}
      <nav className="bg-white border-b border-slate-200 px-4 py-4 sticky top-0 z-50">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg text-white">
              <i className="fas fa-shield-halved text-xl"></i>
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">EthicsGuard</h1>
          </div>
          {result && (
            <button 
              onClick={reset}
              className="text-sm font-semibold text-slate-500 hover:text-indigo-600 transition-colors"
            >
              Start New Review
            </button>
          )}
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-grow max-w-5xl mx-auto w-full p-4 md:p-8">
        {!result ? (
          <div className="grid lg:grid-cols-12 gap-8">
            {/* Left: Introduction */}
            <div className="lg:col-span-5 space-y-6">
              <h2 className="text-4xl font-extrabold text-slate-900 leading-tight">
                Review your Ethical Approval form <span className="text-indigo-600">in seconds.</span>
              </h2>
              <p className="text-lg text-slate-600 leading-relaxed">
                Ensure your research methodology, participant groups, and data management plans align with institutional requirements. Our AI assistant analyzes for inconsistencies and checklist gaps.
              </p>

              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <h3 className="font-bold text-slate-800 mb-4 flex items-center">
                  <i className="fas fa-list-check mr-2 text-indigo-500"></i> Review Focus Areas
                </h3>
                <ul className="space-y-3 text-sm text-slate-600">
                  <li className="flex items-center gap-2">
                    <i className="fas fa-check text-green-500"></i> Methodology & Claims Consistency
                  </li>
                  <li className="flex items-center gap-2">
                    <i className="fas fa-check text-green-500"></i> Table 3 & 6 Deep Dive
                  </li>
                  <li className="flex items-center gap-2">
                    <i className="fas fa-check text-green-500"></i> Data Management & GDPR
                  </li>
                  <li className="flex items-center gap-2">
                    <i className="fas fa-check text-green-500"></i> Participant Risk & Mitigation
                  </li>
                </ul>
              </div>
            </div>

            {/* Right: Input Form */}
            <div className="lg:col-span-7 space-y-6">
              <div className="bg-white p-6 md:p-8 rounded-3xl shadow-xl border border-slate-100">
                <div className="space-y-6">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">
                      Paste form content or notes here
                    </label>
                    <textarea 
                      value={inputText}
                      onChange={(e) => setInputText(e.target.value)}
                      placeholder="Enter the text of your methodology, table details, or participant plans..."
                      className="w-full h-48 p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all resize-none text-slate-800"
                    />
                  </div>

                  <FileUpload onFilesSelected={handleFiles} files={attachments} />

                  {error && (
                    <div className="bg-red-50 text-red-600 p-4 rounded-xl text-sm font-medium border border-red-100 flex items-center gap-2">
                      <i className="fas fa-circle-exclamation"></i>
                      {error}
                    </div>
                  )}

                  <button 
                    onClick={handleSubmit}
                    disabled={isAnalyzing}
                    className="w-full bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white font-bold py-4 rounded-xl transition-all shadow-lg shadow-indigo-200 flex items-center justify-center gap-2"
                  >
                    {isAnalyzing ? (
                      <>
                        <i className="fas fa-spinner fa-spin"></i>
                        Analyzing Submission...
                      </>
                    ) : (
                      <>
                        <i className="fas fa-magnifying-glass"></i>
                        Run Ethics Review
                      </>
                    )}
                  </button>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <AnalysisView result={result} />
        )}
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 py-8 px-4 mt-auto">
        <div className="max-w-5xl mx-auto text-center space-y-4">
          <p className="text-slate-400 text-xs">
            © 2024 EthicsGuard AI Reviewer. This tool provides automated feedback and does not replace formal institutional review.
          </p>
          <div className="flex justify-center gap-6 text-slate-300">
            <i className="fab fa-github"></i>
            <i className="fab fa-linkedin"></i>
            <i className="fab fa-twitter"></i>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

