export interface FeedbackItem {
  section: string;
  status: 'compliant' | 'warning' | 'danger';
  observation: string;
  recommendation: string;
}

export interface AnalysisResult {
  summary: string;
  methodologyCritique: string;
  tableAnalysis: {
    table3: string;
    table6: string;
  };
  inconsistencies: string[];
  checklistFeedback: FeedbackItem[];
  overallVerdict: 'Ready' | 'Needs Revisions' | 'Requires Major Changes';
}

export interface Attachment {
  file: File;
  preview: string;
  base64: string;
  mimeType: string;
  extractedText?: string;
}

import React, { useState } from 'react';

interface FileUploadProps {
  onFilesSelected: (files: FileList) => void;
  files: { preview: string, file: File }[];
}

export const FileUpload: React.FC<FileUploadProps> = ({ onFilesSelected, files }) => {
  const [isDragging, setIsDragging] = useState(false);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setIsDragging(true);
    } else if (e.type === 'dragleave') {
      setIsDragging(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      onFilesSelected(e.dataTransfer.files);
      e.dataTransfer.clearData();
    }
  };

  const getFileIcon = (mime: string) => {
    if (mime.includes('pdf')) return 'fa-file-pdf text-red-500';
    if (mime.includes('word') || mime.includes('officedocument')) return 'fa-file-word text-blue-500';
    return 'fa-file-image text-indigo-500';
  };

  return (
    <div className="w-full">
      <label className="block text-sm font-medium text-slate-700 mb-2">
        Attach your Ethics Form (PDF, DOCX, or Images)
      </label>
      <div 
        className={`flex items-center justify-center w-full transition-all duration-200 ${isDragging ? 'scale-[1.02]' : ''}`}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
      >
        <label className={`flex flex-col items-center justify-center w-full h-40 border-2 border-dashed rounded-xl cursor-pointer transition-colors ${isDragging ? 'border-indigo-500 bg-indigo-50' : 'border-slate-300 bg-white hover:bg-slate-50'}`}>
          <div className="flex flex-col items-center justify-center pt-5 pb-6">
            <i className={`fas fa-cloud-upload-alt text-3xl mb-3 ${isDragging ? 'text-indigo-600' : 'text-indigo-400'}`}></i>
            <p className="mb-2 text-sm text-slate-500 font-semibold">
              {isDragging ? 'Drop files now' : 'Click to upload or drag and drop'}
            </p>
            <p className="text-xs text-slate-400">PDF, DOCX, PNG, JPG (Max 5 files)</p>
          </div>
          <input 
            type="file" 
            className="hidden" 
            multiple 
            accept="image/*,.pdf,.doc,.docx,application/pdf,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document" 
            onChange={(e) => e.target.files && onFilesSelected(e.target.files)} 
          />
        </label>
      </div>

      {files.length > 0 && (
        <div className="mt-4 grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-3">
          {files.map((item, idx) => (
            <div key={idx} className="relative group p-2 border border-slate-200 rounded-lg bg-white shadow-sm">
              {item.file.type.startsWith('image/') ? (
                <img 
                  src={item.preview} 
                  className="w-full h-16 object-cover rounded mb-1" 
                  alt="Upload preview" 
                />
              ) : (
                <div className="w-full h-16 flex items-center justify-center bg-slate-50 rounded mb-1">
                   <i className={`fas ${getFileIcon(item.file.type)} text-2xl`}></i>
                </div>
              )}
              <p className="text-[10px] text-slate-500 truncate font-medium">{item.file.name}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { Attachment } from "../types";

export const analyzeEthicsForm = async (text: string, attachments: Attachment[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const parts: any[] = [];

  // Combine user text and extracted text from DOCX
  let combinedText = `Student Submission Content:\n${text}\n\n`;
  attachments.forEach(att => {
    if (att.extractedText) {
      combinedText += `--- EXTRACTED FROM DOCUMENT (${att.file.name}) ---\n${att.extractedText}\n\n`;
    }
  });

  parts.push({ text: combinedText });

  // Add PDF or Image files
  attachments.forEach(att => {
    if (att.mimeType === 'application/pdf' || att.mimeType.startsWith('image/')) {
      parts.push({
        inlineData: {
          mimeType: att.mimeType,
          data: att.base64.split(',')[1]
        }
      });
    }
  });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts }],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        thinkingConfig: { thinkingBudget: 32768 },
        responseMimeType: "application/json"
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

import React, { useState, useCallback } from 'react';
import { FileUpload } from './components/FileUpload';
import { AnalysisView } from './components/AnalysisView';
import { analyzeEthicsForm } from './services/geminiService';
import { AnalysisResult, Attachment } from './types';

declare const mammoth: any;

const App: React.FC = () => {
  const [inputText, setInputText] = useState('');
  const [attachments, setAttachments] = useState<Attachment[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const processFile = async (file: File): Promise<Attachment> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();

      reader.onloadend = async () => {
        const base64 = reader.result as string;
        let extractedText = '';

        // If it's a docx file, try to extract text locally for better context
        if (file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' || file.name.endsWith('.docx')) {
          try {
            const arrayBuffer = reader.result as ArrayBuffer;
            const result = await mammoth.extractRawText({ arrayBuffer });
            extractedText = result.value;
          } catch (e) {
            console.error("Mammoth failed to parse docx", e);
          }
        }

        resolve({
          file,
          preview: URL.createObjectURL(file),
          base64: typeof reader.result === 'string' ? reader.result : '',
          mimeType: file.type || 'application/octet-stream',
          extractedText
        });
      };

      if (file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' || file.name.endsWith('.docx')) {
        reader.readAsArrayBuffer(file);
      } else {
        reader.readAsDataURL(file);
      }
    });
  };

  const handleFiles = useCallback(async (files: FileList) => {
    const newAttachments: Attachment[] = [];
    const filesArray = Array.from(files).slice(0, 5);

    for (const file of filesArray) {
      try {
        const processed = await processFile(file);
        newAttachments.push(processed);
      } catch (err) {
        console.error("Error processing file:", file.name, err);
      }
    }

    setAttachments(prev => [...prev, ...newAttachments].slice(0, 5));
  }, []);

  const handleSubmit = async () => {
    if (!inputText && attachments.length === 0) {
      setError("Please provide some text or upload your ethics form (PDF/DOCX/Images).");
      return;
    }

    setIsAnalyzing(true);
    setError(null);
    setResult(null);

    try {
      const analysis = await analyzeEthicsForm(inputText, attachments);
      setResult(analysis);
    } catch (err: any) {
      setError(err.message || "Failed to analyze the form. Please check your API configuration.");
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const reset = () => {
    setResult(null);
    setInputText('');
    setAttachments([]);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Navigation */}
      <nav className="bg-white border-b border-slate-200 px-4 py-4 sticky top-0 z-50">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg text-white">
              <i className="fas fa-shield-halved text-xl"></i>
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">EthicsGuard</h1>
          </div>
          {result && (
            <button 
              onClick={reset}
              className="text-sm font-semibold text-slate-500 hover:text-indigo-600 transition-colors"
            >
              Start New Review
            </button>
          )}
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-grow max-w-5xl mx-auto w-full p-4 md:p-8">
        {!result ? (
          <div className="grid lg:grid-cols-12 gap-8">
            {/* Left: Introduction */}
            <div className="lg:col-span-5 space-y-6">
              <h2 className="text-4xl font-extrabold text-slate-900 leading-tight">
                Review your Research Ethics <span className="text-indigo-600">accurately.</span>
              </h2>
              <p className="text-lg text-slate-600 leading-relaxed">
                Upload your PDF or Word document. We focus specifically on your methodology and <span className="font-semibold text-slate-800 underline decoration-indigo-300">Tables 3 & 6</span> to find inconsistencies.
              </p>

