import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";
import { Attachment } from "../types";

export const analyzeEthicsForm = async (attachments: Attachment[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const parts: any[] = [];

  // Combine extracted text from documents
  let combinedText = `Student Submission Analysis:\n\n`;
  attachments.forEach(att => {
    if (att.extractedText) {
      combinedText += `--- EXTRACTED FROM DOCUMENT (${att.file.name}) ---\n${att.extractedText}\n\n`;
    }
  });

  parts.push({ text: combinedText });

  // Add PDF or Image files for visual analysis
  attachments.forEach(att => {
    if (att.mimeType === 'application/pdf' || att.mimeType.startsWith('image/')) {
      parts.push({
        inlineData: {
          mimeType: att.mimeType,
          data: att.base64.split(',')[1]
        }
      });
    }
  });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts }],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        thinkingConfig: { thinkingBudget: 32768 },
        responseMimeType: "application/json"
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

